def enhance_headings(content):
    """微信小标题智能识别"""
    soup = BeautifulSoup(content, 'html.parser')

    # 微信小标题常见特征
    heading_patterns = [
        {'style': re.compile(r'font-size:\s*19px')},  # 标准小标题字号
        {'style': re.compile(r'color:\s*#(666666|888888)')},  # 灰色文字
        {'style': re.compile(r'font-weight:\s*bold')},  # 加粗文本
        {'class': re.compile(r'rich_media_(title|subtitle)')}  # 官方类名
    ]

    for element in soup.find_all(['span', 'div', 'p']):
        # 检测小标题特征
        is_heading = any(
            (pattern.get('style') and element.get('style') and pattern['style'].search(element['style'])) or
            (pattern.get('class') and element.get('class') and any(pattern['class'].match(c) for c in element['class']))
            for pattern in heading_patterns
        )

        # 添加标题标记
        if is_heading:
            # 保留原始样式的同时添加类名
            element['class'] = element.get('class', []) + ['enhanced-heading']
            # 添加装饰性内容（可选）
            element.insert_before(soup.new_tag('hr', style="margin: 1.5em 0; border: 1px solid #eee;"))

    return str(soup)

# 在保存HTML函数中添加 ↓
html_template = html_template.replace('</style>', '''
